CREATE OR REPLACE FUNCTION search_similar_content(embedding_vector vector, similarity_threshold float, result_limit int, filter_user_id text DEFAULT NULL, filter_start_date text DEFAULT NULL, filter_end_date text DEFAULT NULL)
    RETURNS TABLE(
        ROLE text,
        src_id int,
        content text,
        src_type text,
        prox float,
        cid int,
        ts timestamptz
    )
    AS $$
BEGIN
    RETURN QUERY
    -- Search for semantically similar content
    -- Parameters:
    -- embedding_vector: embedding vector
    -- similarity_threshold: minimum similarity threshold
    -- result_limit: limit of results
    -- filter_user_id: user_id (optional, can be NULL)
    -- filter_start_date: start_date (optional, can be NULL, e.g., '2025-06-01')
    -- filter_end_date: end_date (optional, can be NULL, e.g., '2025-06-05')
    WITH
    -- Step 1a: Find similar messages.
    similar_messages_unfiltered AS(
        SELECT
            m.id AS source_id,
            m.conversation_id,
            m.role,
            m.created_at,
            1 -(e.embedding <=> embedding_vector) AS similarity
        FROM
            memories e
            JOIN messages m ON e.source_id = m.id
        WHERE
            e.source = 'message'
            AND 1 -(e.embedding <=> embedding_vector) > similarity_threshold
            -- Add conditional time window filters.
            AND(filter_start_date::text IS NULL
                OR m.created_at >=(filter_start_date::text)::timestamptz)
            AND(filter_end_date::text IS NULL
                OR m.created_at <=(filter_end_date::text)::timestamptz)
),
-- Step 1b: Find similar summaries, with the same conditional logic.
similar_summaries_unfiltered AS(
    SELECT
        s.id AS source_id,
        s.conversation_id,
        1 -(e.embedding <=> embedding_vector) AS similarity
    FROM
        memories e
        JOIN summaries s ON e.source_id = s.id
    WHERE
        e.source = 'summary'
        AND 1 -(e.embedding <=> embedding_vector) > similarity_threshold
        -- Add conditional time window filters.
        AND(filter_start_date::text IS NULL
            OR s.created_at >=(filter_start_date::text)::timestamptz)
        AND(filter_end_date::text IS NULL
            OR s.created_at <=(filter_end_date::text)::timestamptz)
),
-- Step 1c: Find similar search_topic_syntheses
similar_search_topics_unfiltered AS(
    SELECT
        st.id AS source_id,
        st.conversation_id,
        1 -(e.embedding <=> embedding_vector) AS similarity
    FROM
        memories e
        JOIN search_topic_syntheses st ON e.source_id = st.id
    WHERE
        e.source = 'search'
        AND 1 -(e.embedding <=> embedding_vector) > similarity_threshold
        -- Add conditional time window filters.
        AND(filter_start_date::text IS NULL
            OR st.created_at >=(filter_start_date::text)::timestamptz)
        AND(filter_end_date::text IS NULL
            OR st.created_at <=(filter_end_date::text)::timestamptz)
),
-- Step 1d: Find similar file documents
similar_documents_unfiltered AS(
    SELECT
        d.id AS source_id,
        m.conversation_id,
        1 -(e.embedding <=> embedding_vector) AS similarity
    FROM
        memories e
        JOIN documents d ON e.source_id = d.id
        JOIN messages m ON d.message_id = m.id
    WHERE
        e.source = 'document'
        AND 1 -(e.embedding <=> embedding_vector) > similarity_threshold
        -- Add conditional time window filters.
        AND(filter_start_date::text IS NULL
            OR d.created_at >=(filter_start_date::text)::timestamptz)
        AND(filter_end_date::text IS NULL
            OR d.created_at <=(filter_end_date::text)::timestamptz)
),
-- Step 1e: CTE for user-level filtering.
filtered_convos AS(
    SELECT
        id
    FROM
        conversations
    WHERE
        user_id = filter_user_id::text
),
-- Step 1f: Apply proper user filtering only (no conversation filtering)
similar_messages AS(
    SELECT
        *
    FROM
        similar_messages_unfiltered ssu
    WHERE
        -- If no user_id provided, show all
(filter_user_id::text IS NULL)
        OR
        -- If user_id provided, filter by user's conversations
(ssu.conversation_id IN(
                SELECT
                    id
                FROM
                    filtered_convos))
),
-- Step 2: Use LAG and LEAD to find sequential message pairs
message_context AS(
    SELECT
        sm.source_id,
        sm.conversation_id,
        sm.role,
        sm.similarity,
        sm.created_at,
        -- Get the next message ID, role, and created_at
        LEAD(sm.source_id) OVER(PARTITION BY sm.conversation_id ORDER BY sm.source_id,
            sm.created_at) AS next_message_id,
        LEAD(sm.role) OVER(PARTITION BY sm.conversation_id ORDER BY sm.source_id,
            sm.created_at) AS next_message_role,
    LEAD(sm.created_at) OVER(PARTITION BY sm.conversation_id ORDER BY sm.source_id,
        sm.created_at) AS next_message_created_at,
    -- Get the previous message ID, role, and created_at
    LAG(sm.source_id) OVER(PARTITION BY sm.conversation_id ORDER BY sm.source_id,
        sm.created_at) AS prev_message_id,
    LAG(sm.role) OVER(PARTITION BY sm.conversation_id ORDER BY sm.source_id,
        sm.created_at) AS prev_message_role,
    LAG(sm.created_at) OVER(PARTITION BY sm.conversation_id ORDER BY sm.source_id,
        sm.created_at) AS prev_message_created_at
FROM
    similar_messages sm
ORDER BY
    sm.conversation_id,
    sm.source_id
),
message_pairs AS(
    -- Find user messages with their next assistant response
    SELECT
        mc.source_id AS first_message_id,
        'user' AS first_message_role,
        mc.created_at AS first_message_created_at,
        mc.next_message_id AS second_message_id,
        'assistant' AS second_message_role,
        mc.next_message_created_at AS second_message_created_at,
        mc.conversation_id,
        mc.similarity,
        'user_first' AS pair_type -- Mark that user message comes first
    FROM
        message_context mc
    WHERE
        mc.role = 'user'
        AND mc.next_message_role = 'assistant'
        AND mc.next_message_id IS NOT NULL
    UNION ALL
    -- Find assistant messages with their previous user query
    SELECT
        mc.prev_message_id AS first_message_id,
        'user' AS first_message_role,
        mc.prev_message_created_at AS first_message_created_at,
        mc.source_id AS second_message_id,
        'assistant' AS second_message_role,
        mc.created_at AS second_message_created_at,
        mc.conversation_id,
        mc.similarity,
        'assistant_match' AS pair_type -- Mark that assistant message was the match
    FROM
        message_context mc
    WHERE
        mc.role = 'assistant'
        AND mc.prev_message_role = 'user'
        AND mc.prev_message_id IS NOT NULL
),
-- Step 3: Deduplicate message pairs by prioritizing pairs with higher similarity
-- and ensuring we don't include the same message in multiple pairs
deduplicated_message_pairs AS(
    SELECT
        first_message_id,
        first_message_role,
        first_message_created_at,
        second_message_id,
        second_message_role,
        second_message_created_at,
        mp.conversation_id,
        mp.similarity,
        pair_type,
        -- For each pair of messages, keep the one with the highest similarity
        ROW_NUMBER() OVER(PARTITION BY first_message_id,
            second_message_id ORDER BY mp.similarity DESC) AS exact_pair_rank,
        -- For each message, keep only one pair it belongs to (the highest similarity)
        ROW_NUMBER() OVER(PARTITION BY first_message_id ORDER BY mp.similarity DESC) AS first_message_rank,
        ROW_NUMBER() OVER(PARTITION BY second_message_id ORDER BY mp.similarity DESC) AS second_message_rank
    FROM
        message_pairs mp
),
-- Step 4: Prepare message pairs to fetch with their similarity scores
-- Always putting user messages first, assistant messages second
message_results_to_fetch AS(
    -- Add first message (user)
    SELECT
        first_message_id AS source_id,
        'message' AS source_type,
        dmp.similarity,
        dmp.conversation_id,
        1 AS pair_order, -- User message first
        dmp.similarity AS original_similarity,
        CONCAT(first_message_id, '-', second_message_id) AS pair_key -- Create unique pair key
    FROM
        deduplicated_message_pairs dmp
    WHERE
        exact_pair_rank = 1 -- Only the highest similarity for this exact pair
        AND first_message_rank = 1 -- Only include this message in one pair (highest similarity)
        AND second_message_rank = 1 -- Only include this message in one pair (highest similarity)
        AND first_message_role = 'user' -- Verify it's a user message
        AND second_message_role = 'assistant' -- Verify it's paired with an assistant message
    UNION ALL
    -- Add second message (assistant)
    SELECT
        second_message_id AS source_id,
        'message' AS source_type,
        dmp.similarity, -- Use same similarity as original
        dmp.conversation_id,
        2 AS pair_order, -- Assistant message second
        dmp.similarity AS original_similarity,
        CONCAT(first_message_id, '-', second_message_id) AS pair_key -- Same pair key to match
    FROM
        deduplicated_message_pairs dmp
    WHERE
        exact_pair_rank = 1 -- Only the highest similarity for this exact pair
        AND first_message_rank = 1 -- Only include this message in one pair (highest similarity)
        AND second_message_rank = 1 -- Only include this message in one pair (highest similarity)
        AND first_message_role = 'user' -- Verify it's a user message
        AND second_message_role = 'assistant' -- Verify it's paired with an assistant message
),
-- Step 5: Include the summaries
summary_results_to_fetch AS(
    SELECT
        ssu.source_id,
        'summary' AS source_type,
        ssu.similarity,
        ssu.conversation_id,
        0 AS pair_order, -- Summaries are standalone
        ssu.similarity AS original_similarity,
        CONCAT('summary-', ssu.source_id) AS pair_key -- Each summary is its own group
    FROM
        similar_summaries_unfiltered ssu
    WHERE
    -- Apply proper user filtering for summaries (no conversation filtering)
(filter_user_id::text IS NULL)
    OR(ssu.conversation_id IN(
            SELECT
                id
            FROM
                filtered_convos))
),
-- step 6, Include the search topic syntheses
search_results_to_fetch AS(
    SELECT
        ss.source_id,
        'search' AS source_type,
        ss.similarity,
        ss.conversation_id,
        0 AS pair_order, -- Search results are standalone
        ss.similarity AS original_similarity,
        CONCAT('search-', ss.source_id) AS pair_key -- Each search result is its own group
    FROM
        similar_search_topics_unfiltered ss
    WHERE
    -- Apply proper user filtering for search topics (no conversation filtering)
(filter_user_id::text IS NULL)
    OR(ss.conversation_id IN(
            SELECT
                id
            FROM
                filtered_convos))
),
-- step 7, Include the file documents
document_results_to_fetch AS(
    SELECT
        sa.source_id,
        'document' AS source_type,
        sa.similarity,
        sa.conversation_id,
        0 AS pair_order, -- documents are standalone
        sa.similarity AS original_similarity,
        CONCAT('document-', sa.source_id) AS pair_key -- Each document is its own group
    FROM
        similar_documents_unfiltered sa
    WHERE
    -- Apply proper user filtering for documents (no conversation filtering)
(filter_user_id::text IS NULL)
    OR(sa.conversation_id IN(
            SELECT
                id
            FROM
                filtered_convos))
),
-- Step 8: Combine message pairs, summaries, search results, and documents
all_results_to_fetch AS(
    SELECT
        *
    FROM
        message_results_to_fetch
    UNION ALL
    SELECT
        *
    FROM
        summary_results_to_fetch
    UNION ALL
    SELECT
        *
    FROM
        search_results_to_fetch
    UNION ALL
    SELECT
        *
    FROM
        document_results_to_fetch
),
-- Step 9: Prepare final results
-- Keep the original ordering and uniqueness ensured from previous steps
unique_results AS(
    SELECT
        source_id,
        source_type,
        similarity,
        conversation_id,
        pair_order,
        pair_key,
        original_similarity,
        -- Generate a rank for the complete dataset to aid in LIMIT application
        ROW_NUMBER() OVER(ORDER BY original_similarity DESC,
            pair_key,
            pair_order) AS global_rank
FROM
    all_results_to_fetch
),
-- Step 9: Fetch the final content with proper ordering
-- First apply LIMIT to pairs (by their highest similarity), then ensure both messages in each pair are included
limited_pairs AS(
    -- Use a simple approach to limit the number of pairs
    -- Get the top N pairs based on similarity
    SELECT
        pair_key
    FROM
        unique_results
    GROUP BY
        pair_key
    ORDER BY
        MAX(similarity) DESC
    LIMIT result_limit
)
SELECT
    COALESCE(m.role, 'system') AS role,
u.source_id,
COALESCE(mc.text_content, s.content, ss.synthesis, d.text_content, d.filename) AS content,
u.source_type,
u.similarity,
COALESCE(m.conversation_id, s.conversation_id, ss.conversation_id, msg.conversation_id) AS conversation_id,
COALESCE(m.created_at, s.created_at, ss.created_at, d.created_at) AS created_at
FROM
    unique_results u
    LEFT JOIN messages m ON u.source_id = m.id
        AND u.source_type = 'message'
    LEFT JOIN message_contents mc ON m.id = mc.message_id
        AND u.source_type = 'message'
    LEFT JOIN summaries s ON u.source_id = s.id
        AND u.source_type = 'summary'
    LEFT JOIN search_topic_syntheses ss ON u.source_id = ss.id
        AND u.source_type = 'search'
    LEFT JOIN documents d ON u.source_id = d.id
        AND u.source_type = 'document'
    LEFT JOIN messages msg ON d.message_id = msg.id
        AND u.source_type = 'document'
WHERE
    u.pair_key IN(
        SELECT
            pair_key
        FROM
            limited_pairs)
ORDER BY
    u.similarity DESC, -- Sort by highest similarity first
    COALESCE(m.conversation_id, s.conversation_id, ss.conversation_id, msg.conversation_id), -- Keep conversation pairs together
    COALESCE(m.created_at, s.created_at, ss.created_at, d.created_at);
    -- Maintain chronological order within conversations
END;
$$
LANGUAGE plpgsql;

